const crypto = require("node:crypto");
const { Buffer } = require("node:buffer");

module.exports = async function probe() {
    const hash = crypto.createHash("sha256");
    hash.update("hello");
    const sha256 = await hash.digest("hex");
    const random = crypto.randomBytes(16);
    const left = Buffer.from("12345678901234567890", "utf8");
    const right = Buffer.from("12345678901234567890", "utf8");
    const timingEq = crypto.timingSafeEqual(left, right);
    return {
        sha256: sha256,
        randomLen: random.length,
        timingEq: timingEq,
    };
};
